export function parseGroupByCubeOrRollup(groupBy: GroupByArg<any, any, any>, grouping: 'cube' | 'rollup'): GroupByItemNode[] {
  groupBy = isFunction(groupBy) ? groupBy(expressionBuilder()) : groupBy
  return [GroupByItemNode.create(parseReferenceExpressionOrList(groupBy)[0], grouping, [parseReferenceExpressionOrList(groupBy)])]
}

export function parseGroupingSets(sets: ReadonlyArray<GroupByArg<any, any, any>>): GroupByItemNode[] {
  return [GroupByItemNode.create(parseReferenceExpressionOrList(sets[0] ?? [])[0], 'grouping sets', sets.map((set) => parseReferenceExpressionOrList(isFunction(set) ? set(expressionBuilder()) : set)))]
}

