import type { KyselyPlugin, PluginTransformQueryArgs, PluginTransformResultArgs } from '../kysely-plugin.js'

/** Removes explicit RANGE frames that duplicate SQL's implicit window-frame default. */
export class SimplifyFramePlugin implements KyselyPlugin {
  readonly #transformer = new SimplifyFrameTransformer()
  transformQuery(args: PluginTransformQueryArgs): RootOperationNode { return this.#transformer.transformNode(args.node, args.queryId) }
  transformResult(args: PluginTransformResultArgs): Promise<QueryResult<UnknownRow>> { return Promise.resolve(args.result) }
}

class SimplifyFrameTransformer extends OperationNodeTransformer {
  override transformOver(node: OverNode, queryId?: any): OverNode {
    node = super.transformOver(node, queryId)
    const frame = node.frame
    if (!frame || frame.unit !== 'range' || frame.exclusion || frame.start.offset || frame.end?.offset) return node
    const isDefault = node.orderBy
      ? frame.start.type === 'unbounded preceding' && !frame.end
      : frame.start.type === 'unbounded preceding' && frame.end?.type === 'unbounded following'
    return isDefault ? { ...node, frame: undefined } : node
  }
}
